// ============================================================
// Node: Init
// Gera correlation_id, registra início da execução no PostgreSQL
// ============================================================
const { v4: uuidv4 } = require('uuid');

const correlationId = uuidv4();
const startedAt = new Date().toISOString();
const executionId = $execution.id;

// Persiste início da execução — será atualizado ao final
// A query real é feita no node PostgreSQL subsequente
// Aqui apenas preparamos os metadados
return [{
  json: {
    correlationId,
    startedAt,
    executionId,
    workflowName: 'WF-01-match-collector',
    circuitBreakerKey: 'wcic:circuit:wf01:football-data',
    errorCounterKey: 'wcic:errors:wf01:football-data',
    teamIdMapCacheKey: 'wcic:cache:team-id-map',
    activeMatchesKey: 'wcic:active_matches'
  }
}];

// ============================================================
// Node: Handle Primary API Error
// Incrementa contador de erros e decide entre fallback ou circuit open
// ============================================================
const errorCounterKey = 'wcic:errors:wf01:football-data';
const circuitKey = 'wcic:circuit:wf01:football-data';

// O valor do contador será lido no próximo node Redis
// Aqui apenas preparamos o contexto para a decisão
const errorData = $input.first().json;

return [{
  json: {
    ...$('Init').first().json,
    errorCounterKey,
    circuitKey,
    apiError: errorData.error || 'HTTP error from Football-Data API',
    timestamp: new Date().toISOString()
  }
}];

// ============================================================
// Node: Normalize Payload
// Converte resposta da API (Football-Data ou RapidAPI) para
// o schema wcic.matches. Suporta ambos os formatos.
// ============================================================

const initData = $('Init').first().json;
const apiResponse = $input.first().json;

// Detecta qual API respondeu pelo formato
const isFootballData = apiResponse.body?.matches !== undefined || apiResponse.matches !== undefined;
const isRapidApi = apiResponse.response !== undefined;

const STATUS_MAP_FD = {
  'SCHEDULED':   'scheduled',
  'TIMED':       'scheduled',
  'IN_PLAY':     'live',
  'PAUSED':      'halftime',
  'FINISHED':    'finished',
  'POSTPONED':   'postponed',
  'CANCELLED':   'cancelled',
  'SUSPENDED':   'suspended',
};

const STATUS_MAP_RA = {
  'NS':    'scheduled',  // Not Started
  '1H':   'live',        // First Half
  'HT':   'halftime',    // Half Time
  '2H':   'live',        // Second Half
  'ET':   'live',        // Extra Time
  'P':    'live',        // Penalty in Progress
  'FT':   'finished',    // Full Time
  'AET':  'finished',    // After Extra Time
  'PEN':  'finished',    // After Penalties
  'SUSP': 'suspended',
  'PST':  'postponed',
  'CANC': 'cancelled',
};

const STAGE_MAP_FD = {
  'GROUP_STAGE':    (m) => `group_${(m.group || 'Group A').replace('Group ', '').toLowerCase()}`,
  'LAST_32':        () => 'round_of_32',
  'LAST_16':        () => 'round_of_16',
  'QUARTER_FINALS': () => 'quarter_final',
  'SEMI_FINALS':    () => 'semi_final',
  'THIRD_PLACE':    () => 'third_place',
  'FINAL':          () => 'final',
};

let rawMatches = [];
let sourceApi = 'football-data';

if (isFootballData) {
  const body = apiResponse.body || apiResponse;
  rawMatches = body.matches || [];
  sourceApi = 'football-data';
} else if (isRapidApi) {
  rawMatches = apiResponse.response || [];
  sourceApi = 'rapidapi';
}

if (rawMatches.length === 0) {
  return [{ json: { matches: [], sourceApi, correlationId: initData.correlationId, totalMatches: 0 } }];
}

const normalizedMatches = [];
const errors = [];

for (const raw of rawMatches) {
  try {
    let match;

    if (sourceApi === 'football-data') {
      const stageResolver = STAGE_MAP_FD[raw.stage];
      if (!stageResolver) {
        errors.push({ external_id: raw.id, error: `Unknown stage: ${raw.stage}` });
        continue;
      }
      match = {
        external_id:    String(raw.id),
        external_home_id: String(raw.homeTeam.id),
        external_away_id: String(raw.awayTeam.id),
        stage:          stageResolver(raw),
        scheduled_at:   raw.utcDate,
        status:         STATUS_MAP_FD[raw.status] || 'scheduled',
        home_score:     raw.score?.fullTime?.home ?? null,
        away_score:     raw.score?.fullTime?.away ?? null,
        home_score_ht:  raw.score?.halfTime?.home ?? null,
        away_score_ht:  raw.score?.halfTime?.away ?? null,
        referee:        raw.referees?.[0]?.name ?? null,
        source_api:     'football-data',
        raw_payload:    raw,
        // winner resolvido pelo node PostgreSQL com base nos IDs internos
        score_winner:   raw.score?.winner ?? null,
      };
    } else {
      // RapidAPI format
      const fixture = raw.fixture || raw;
      const league = raw.league || {};
      const teams = raw.teams || {};
      const goals = raw.goals || {};
      const score = raw.score || {};

      const stageRaw = league.round || 'Group Stage';
      let stage = 'group_a';
      if (stageRaw.toLowerCase().includes('group')) {
        const letter = (stageRaw.match(/group\s+([a-l])/i) || [])[1] || 'a';
        stage = `group_${letter.toLowerCase()}`;
      } else if (stageRaw.includes('Round of 32')) stage = 'round_of_32';
      else if (stageRaw.includes('Round of 16')) stage = 'round_of_16';
      else if (stageRaw.includes('Quarter')) stage = 'quarter_final';
      else if (stageRaw.includes('Semi')) stage = 'semi_final';
      else if (stageRaw.includes('3rd')) stage = 'third_place';
      else if (stageRaw.includes('Final')) stage = 'final';

      match = {
        external_id:     String(fixture.id),
        external_home_id: String(teams.home?.id),
        external_away_id: String(teams.away?.id),
        stage,
        scheduled_at:    fixture.date,
        status:          STATUS_MAP_RA[fixture.status?.short] || 'scheduled',
        home_score:      goals.home ?? null,
        away_score:      goals.away ?? null,
        home_score_ht:   score.halftime?.home ?? null,
        away_score_ht:   score.halftime?.away ?? null,
        referee:         fixture.referee ?? null,
        source_api:      'rapidapi',
        raw_payload:     raw,
        score_winner:    null,
      };
    }

    normalizedMatches.push(match);
  } catch (err) {
    errors.push({ error: err.message, raw_id: raw.id || raw.fixture?.id });
  }
}

return [{
  json: {
    matches: normalizedMatches,
    errors,
    sourceApi,
    correlationId: initData.correlationId,
    totalMatches: normalizedMatches.length,
    totalErrors: errors.length,
  }
}];

// ============================================================
// Node: Resolve Team IDs
// Mapeia external_id da API para UUID interno do PostgreSQL
// Usa cache Redis; se ausente, faz query no banco
// ============================================================

const normalizeData = $('Normalize Payload').first().json;
const cacheResult = $input.first().json;

let teamIdMap = {};

if (cacheResult.value) {
  try {
    teamIdMap = JSON.parse(cacheResult.value);
  } catch (e) {
    // Cache corrompido — será reconstruído via banco
    teamIdMap = {};
  }
}

// Se o mapa não está no cache, será populado pelo node PostgreSQL
// que busca todos os times com external_id
const needsDbFetch = Object.keys(teamIdMap).length === 0;

return [{
  json: {
    ...normalizeData,
    teamIdMap,
    needsDbFetch,
  }
}];

// ============================================================
// Node: Build Team Map from DB
// Constrói o mapa external_id ? UUID e salva no Redis
// ============================================================

const dbRows = $input.all();
const resolveData = $('Resolve Team IDs').first().json;

const teamIdMap = {};
for (const row of dbRows) {
  if (row.json.external_id) {
    teamIdMap[row.json.external_id] = row.json.internal_id;
  }
}

return [{
  json: {
    ...resolveData,
    teamIdMap,
    needsDbFetch: false,
  }
}];

// ============================================================
// Node: Prepare Matches for Batch
// Aplica teamIdMap às partidas normalizadas e filtra inválidas
// Converte array de matches em itens individuais para SplitInBatches
// ============================================================

// Dados chegam de dois caminhos: com DB fetch ou sem
// Pegamos o teamIdMap do nó mais recente disponível
let sourceData;
try {
  sourceData = $('Cache Team Map (24h)').first().json;
} catch(e) {
  sourceData = $('Resolve Team IDs').first().json;
}

const { matches, teamIdMap, correlationId } = sourceData;

if (!matches || matches.length === 0) {
  return [{ json: { skip: true, reason: 'no matches to process', correlationId } }];
}

const prepared = [];
const skipped = [];

for (const match of matches) {
  const homeId = teamIdMap[match.external_home_id];
  const awayId = teamIdMap[match.external_away_id];

  if (!homeId || !awayId) {
    skipped.push({
      external_id: match.external_id,
      reason: `Team not found: home=${match.external_home_id}, away=${match.external_away_id}`
    });
    continue;
  }

  prepared.push({
    ...match,
    home_team_id: homeId,
    away_team_id: awayId,
    correlationId,
  });
}

// Retorna cada partida como item separado para o SplitInBatches
return prepared.map(m => ({ json: m }));

// ============================================================
// Node: Detect Changes
// Compara dados atuais com cache para decidir se UPSERT é necessário
// ============================================================

const match = $('Split in Batches (10)').item.json;
const cacheRaw = $input.item.json;

let cachedData = null;
if (cacheRaw.value) {
  try {
    cachedData = JSON.parse(cacheRaw.value);
  } catch(e) { /* cache corrompido */ }
}

const currentHash = `${match.status}|${match.home_score}|${match.away_score}|${match.home_score_ht}|${match.away_score_ht}`;
const cachedHash = cachedData ? `${cachedData.status}|${cachedData.home_score}|${cachedData.away_score}|${cachedData.home_score_ht}|${cachedData.away_score_ht}` : null;

const hasChanged = !cachedData || currentHash !== cachedHash;
const prevStatus = cachedData?.status || null;

return [{
  json: {
    ...match,
    hasChanged,
    prevStatus,
    currentHash,
  }
}];
